def get_or_create_user_from_saml(name_id, attributes):
    username = name_id
    
    email = attributes.get('email', attributes.get('mail', ''))
    first_name = attributes.get('firstName', attributes.get('givenName', ''))
    last_name = attributes.get('lastName', attributes.get('surname', ''))
    
    if isinstance(email, list):
        email = email[0] if email else ''
    if isinstance(first_name, list):
        first_name = first_name[0] if first_name else ''
    if isinstance(last_name, list):
        last_name = last_name[0] if last_name else ''
    
    user, created = User.objects.get_or_create(
        username=username,
        defaults={
            'email': email,
            'first_name': first_name,
            'last_name': last_name,
        }
    )
    
    if not created:
        user.email = email
        user.first_name = first_name
        user.last_name = last_name
        user.save()
    
    return user


