def saml_acs(request):
    saml_response_b64 = request.POST.get('SAMLResponse')
    
    if not saml_response_b64:
        return HttpResponseBadRequest('Missing SAMLResponse parameter')
    
    saml_response = SAMLResponse(saml_response_b64)
    
    if not saml_response.process():
        return HttpResponseBadRequest('Invalid SAML Response')
    
    try:
        user = get_or_create_user_from_saml(
            saml_response.name_id,
            saml_response.attributes
        )
        
        user.backend = 'django.contrib.auth.backends.ModelBackend'
        login(request, user)
        
        request.session['saml_name_id'] = saml_response.name_id
        request.session['saml_attributes'] = saml_response.attributes
        request.session['saml_session_index'] = saml_response.assertion.get('ID', '')
        
        relay_state = request.POST.get('RelayState', '/')
        
        return redirect(relay_state)
    
    except Exception as e:
        return HttpResponseBadRequest(f'Error processing SAML authentication: {str(e)}')


def saml_metadata(request):
    entity_id = getattr(settings, 'SAML_ENTITY_ID', request.build_absolute_uri('/'))
    acs_url = request.build_absolute_uri('/saml/acs/')
    
    metadata = f'''<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{entity_id}">
  <md:SPSSODescriptor AuthnRequestsSigned="false" WantAssertionsSigned="true"
                      protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                 Location="{acs_url}"
                                 index="1" />
  </md:SPSSODescriptor>
</md:EntityDescriptor>'''
    
    return HttpResponse(metadata, content_type='application/xml')


def saml_login(request):
    idp_sso_url = getattr(settings, 'SAML_IDP_SSO_URL', '')
    entity_id = getattr(settings, 'SAML_ENTITY_ID', request.build_absolute_uri('/'))
    acs_url = request.build_absolute_uri('/saml/acs/')
    
    if not idp_sso_url:
        return HttpResponseBadRequest('SAML IDP SSO URL not configured')
    
    import uuid
    request_id = f'_{uuid.uuid4()}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    authn_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
</samlp:AuthnRequest>'''
    
    encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')
    
    relay_state = request.GET.get('next', '/')
    
    html = f'''
    <html>
    <body onload="document.forms[0].submit()">
        <form method="post" action="{idp_sso_url}">
            <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
            <input type="hidden" name="RelayState" value="{relay_state}" />
            <noscript>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    '''
    
    return HttpResponse(html)


